 51→// ── Serialization ─────────────────────────────────────────────────────────────
 52→
 53→const QUOTE_RE = /\[quote:([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})\]/g
 54→
 55→function escapeHtml(s: string): string {
 56→  return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
 57→}
 58→
 59→/**
 60→ * Convert a [quote:id] serialized string to contenteditable innerHTML.
 61→ * Newlines → <br>; [quote:uuid] tokens → non-editable Q chip spans.
 62→ */
 63→function toHtml(text: string): string {
 64→  const parts = text.split(QUOTE_RE)
 65→  let html = ''
 66→  for (let i = 0; i < parts.length; i++) {
 67→    if (i % 2 === 0) {
 68→      html += escapeHtml(parts[i]).replace(/\n/g, '<br>')
 69→    } else {
 70→      html += `<span style="${CHIP_STYLE}" contenteditable="false" draggable="true" data-quote-id="${parts[i]}">Q</span>`
 71→    }
 72→  }
 73→  return html
 74→}
 75→
 76→/**
 77→ * Walk the contenteditable DOM and return the [quote:id] serialized string.
 78→ * <br> → '\n'; chip spans → [quote:id]; browser-inserted DIVs → '\n' prefix.
 79→ */
 80→function toText(root: Node): string {
 81→  let text = ''
 82→  for (const node of root.childNodes) {
 83→    if (node.nodeType === Node.TEXT_NODE) {
 84→      text += node.textContent ?? ''
 85→    } else if (node.nodeType === Node.ELEMENT_NODE) {
 86→      const el = node as HTMLElement
 87→      if (el.dataset.quoteId) {
 88→        text += `[quote:${el.dataset.quoteId}]`
 89→      } else if (el.tagName === 'BR') {
 90→        text += '\n'
 91→      } else if (el.tagName === 'DIV' || el.tagName === 'P') {
 92→        // Browser wraps new lines in block elements (Chrome) — add newline prefix
 93→        if (node.previousSibling) text += '\n'
 94→        text += toText(el)
 95→      } else {
 96→        text += toText(el)
 97→      }
 98→    }
 99→  }
100→  return text
101→}
102→
103→// ── Cursor offset helpers ─────────────────────────────────────────────────────
104→
105→/** Serialized character length of a single DOM node. */
106→function nodeLen(node: Node): number {
107→  if (node.nodeType === Node.TEXT_NODE) return node.textContent?.length ?? 0
108→  const el = node as HTMLElement
109→  if (el.dataset?.quoteId) return `[quote:${el.dataset.quoteId}]`.length
110→  if (el.tagName === 'BR') return 1
111→  let n = 0
112→  for (const child of el.childNodes) n += nodeLen(child)
113→  return n
114→}
115→
116→/** Compute the serialized character offset for a given DOM Range. */
117→function getOffsetFromRange(div: HTMLElement, range: Range): number {
118→  // Cursor anchored directly on the div (between child elements)
119→  if (range.startContainer === div) {
120→    let off = 0
121→    for (let i = 0; i < range.startOffset; i++) off += nodeLen(div.childNodes[i])
122→    return off
123→  }
124→
125→  let offset = 0
126→  let found = false
127→
128→  function walk(node: Node): void {
129→    if (found) return
130→    if (node === range.startContainer) {
131→      offset += range.startOffset
132→      found = true
133→      return
134→    }
135→    if (node.nodeType === Node.TEXT_NODE) {
136→      offset += node.textContent?.length ?? 0
137→    } else {
138→      const el = node as HTMLElement
139→      if (el.dataset?.quoteId) {
140→        offset += `[quote:${el.dataset.quoteId}]`.length
141→      } else if (el.tagName === 'BR') {
142→        offset += 1
143→      } else {
144→        for (const child of el.childNodes) {
145→          walk(child)
146→          if (found) return
147→        }
148→      }
149→    }
150→  }
151→
152→  for (const child of div.childNodes) {
153→    walk(child)
154→    if (found) break
155→  }
156→  return offset
157→}
158→
159→/**
160→ * Return the cursor's position as an offset in the serialized (text) string.
161→ * Quote chips count as their full [quote:uuid] token length (~44 chars).
162→ */
163→function getOffset(div: HTMLElement): number {
164→  const sel = window.getSelection()
165→  if (!sel || sel.rangeCount === 0) return 0
166→  return getOffsetFromRange(div, sel.getRangeAt(0))
167→}
168→
169→/** Return the serialized character offset marking the start of a given child node. */
170→function getNodeOffset(div: HTMLElement, targetNode: Node): number {
171→  let offset = 0
172→  let found = false
173→
174→  function walk(node: Node): void {
175→    if (found) return
176→    if (node === targetNode) { found = true; return }
177→    if (node.nodeType === Node.TEXT_NODE) {
178→      offset += node.textContent?.length ?? 0
179→    } else {
180→      const el = node as HTMLElement
181→      if (el.dataset?.quoteId) {
182→        offset += `[quote:${el.dataset.quoteId}]`.length
183→      } else if (el.tagName === 'BR') {
184→        offset += 1
185→      } else {
186→        for (const child of el.childNodes) {
187→          walk(child)
188→          if (found) return
189→        }
190→      }
191→    }
192→  }
193→
194→  for (const child of div.childNodes) {
195→    walk(child)
196→    if (found) break
197→  }
198→  return offset
199→}
